Here's a modern MSTest test class covering async success, failure, and cancellation:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    [Timeout(5000)] // fail-safe so a hung test doesn't block CI
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            });
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var handler = new MockHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        // Handler that delays long enough for cancellation to fire
        var handler = new MockHttpMessageHandler(delay: TimeSpan.FromSeconds(10));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Lightweight mock — avoids external mocking libraries
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage? _response;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(HttpResponseMessage response)
            => _response = response;

        public MockHttpMessageHandler(TimeSpan delay)
            => _delay = delay;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken); // respects token

            return _response ?? new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `async Task` test methods | MSTest natively awaits them — no `.Result` / `.GetAwaiter()` needed |
| `[Timeout(5000)]` | Guards against hangs; fails the test after 5 s |
| `CancellationTokenSource` | Verifies your code forwards the token to `HttpClient` |
| `Assert.ThrowsExceptionAsync` | Async-aware exception assertion (not `ThrowsException`) |
| Custom `HttpMessageHandler` | Avoids mocking `HttpClient` directly (which isn't designed for it) |

The mock handler is the critical piece — `HttpClient` delegates all work to its inner `HttpMessageHandler`, so substituting that gives you full control without any third-party libraries.
